#include<bits/stdc++.h>
using namespace std;
int z[20000010],ext[20000010];
char s[20000010],t[20000010];
int main()
{
    scanf("%s%s",t,s);
    int m=strlen(t),n=strlen(s);
    z[0]=n;
    int l=0,r=0;
    for(int i=1;i<n;i++)
    {
        if(i<=r&&z[i-l]<r-i+1)
        {
            z[i]=z[i-l];
        }
        else
        {
            z[i]=max(0,r-i+1);
            while(i+z[i]<n&&s[z[i]]==s[i+z[i]])
            {
                z[i]++;
            }
        }
        if(i+z[i]-1>r)
        {
            r=i+z[i]-1;
            l=i;
        }
    }
    long long ans=0;
    for(int i=0;i<n;i++)
    {
        ans^=1ll*(i+1)*(z[i]+1);
    }
    printf("%lld\n",ans);
    while(s[ext[0]]==t[ext[0]])
    {
        ext[0]++;
    }
    l=0,r=0;
    for(int i=1;i<m;i++)
    {
        if(i<=r&&z[i-l]<r-i+1)
        {
            ext[i]=z[i-l];
        }
        else
        {
            ext[i]=max(0,r-i+1);
            while(ext[i]<n&&i+ext[i]<m&&s[ext[i]]==t[i+ext[i]])
            {
                ext[i]++;
            }
        }
        if(i+ext[i]-1>r)
        {
            r=i+ext[i]-1;
            l=i;
        }
    }
    ans=0;
    for(int i=0;i<m;i++)
    {
        ans^=1ll*(i+1)*(ext[i]+1);
    }
    printf("%lld",ans);
    return 0;
}
